/**
 * SQLite 数据库集成
 * 用于存储事实台账和角色信息
 */

// 数据库类型定义
export interface Fact {
  id: string
  type: 'power' | 'item' | 'relation' | 'foreshadow'
  subject: string
  object: string
  content: string
  chapterStart: number
  chapterEnd: number
  createdAt: number
}

export interface Role {
  id: string
  name: string
  tags: string[]
  goldenFinger: string
  createdAt: number
}

// 初始化数据库
class Database {
  private db: any | null = null
  private initialized: boolean = false

  constructor() {
    // 在 Electron 环境中使用 better-sqlite3
    if (window.electronAPI) {
      this.initializeElectronDB()
    }
  }

  private async initializeElectronDB() {
    try {
      // 通过 IPC 获取项目根路径
      const projectRoot = await window.electronAPI.getProjectRoot()
      if (!projectRoot) return

      // 数据库文件路径
      const dbPath = `${projectRoot}/facts.db`

      // 检查是否存在数据库
      const exists = await window.electronAPI.exists(dbPath)
      if (!exists) {
        await this.createTables()
      }

      this.initialized = true
    } catch (error) {
      console.error('数据库初始化失败:', error)
    }
  }

  // 创建数据库表
  private async createTables() {
    // 通过 IPC 执行 SQL 创建表
    await window.electronAPI.writeFile(
      `${projectRoot}/facts.db`,
      `CREATE TABLE IF NOT EXISTS facts (
        id TEXT PRIMARY KEY,
        type TEXT NOT NULL,
        subject TEXT NOT NULL,
        object TEXT,
        content TEXT NOT NULL,
        chapter_start INTEGER NOT NULL,
        chapter_end INTEGER NOT NULL,
        created_at INTEGER NOT NULL
      );

      CREATE TABLE IF NOT EXISTS roles (
        id TEXT PRIMARY KEY,
        name TEXT NOT NULL,
        tags TEXT,
        golden_finger TEXT,
        created_at INTEGER NOT NULL
      );`
    )
  }

  // ========== 事实表操作 ==========

  // 添加事实
  async addFact(fact: Omit<Fact, 'id' | 'createdAt'>): Promise<{ success: boolean; id?: string; error?: string }> {
    try {
      const id = crypto.randomUUID()
      const createdAt = Date.now()

      // 执行插入操作
      const insertSQL = `
        INSERT INTO facts (id, type, subject, object, content, chapter_start, chapter_end, created_at)
        VALUES ('${id}', '${fact.type}', '${fact.subject}', '${fact.object || ''}', '${fact.content.replace(/'/g, "''")}', ${fact.chapterStart}, ${fact.chapterEnd}, ${createdAt})
      `

      // 通过 IPC 执行 SQL
      await window.electronAPI.ai.call(insertSQL, { type: 'sql' })

      return { success: true, id }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  }

  // 查询事实
  async getFacts(filters?: { type?: string; subject?: string; chapter?: number }): Promise<Fact[]> {
    try {
      let sql = 'SELECT * FROM facts'
      const conditions: string[] = []

      if (filters?.type) conditions.push(`type = '${filters.type}'`)
      if (filters?.subject) conditions.push(`subject = '${filters.subject}' OR object = '${filters.subject}'`)
      if (filters?.chapter) conditions.push(`chapter_start <= ${filters.chapter} AND (chapter_end >= ${filters.chapter} OR chapter_end IS NULL)`)

      if (conditions.length > 0) sql += ` WHERE ${conditions.join(' AND ')}`
      sql += ' ORDER BY created_at DESC'

      const result = await window.electronAPI.ai.call(sql, { type: 'sql' })
      if (result.success) {
        return JSON.parse(result.content).map((row: any) => ({
          id: row.id,
          type: row.type,
          subject: row.subject,
          object: row.object,
          content: row.content,
          chapterStart: row.chapter_start,
          chapterEnd: row.chapter_end,
          createdAt: row.created_at
        }))
      }
      return []
    } catch (error) {
      console.error('查询事实失败:', error)
      return []
    }
  }

  // 删除事实
  async deleteFact(id: string): Promise<boolean> {
    try {
      const sql = `DELETE FROM facts WHERE id = '${id}'`
      const result = await window.electronAPI.ai.call(sql, { type: 'sql' })
      return result.success
    } catch (error) {
      console.error('删除事实失败:', error)
      return false
    }
  }

  // ========== 角色表操作 ==========

  // 添加角色
  async addRole(role: Omit<Role, 'id' | 'createdAt'>): Promise<{ success: boolean; id?: string; error?: string }> {
    try {
      const id = crypto.randomUUID()
      const createdAt = Date.now()
      const tags = JSON.stringify(role.tags)

      const sql = `
        INSERT INTO roles (id, name, tags, golden_finger, created_at)
        VALUES ('${id}', '${role.name}', '${tags}', '${role.goldenFinger.replace(/'/g, "''")}', ${createdAt})
      `

      const result = await window.electronAPI.ai.call(sql, { type: 'sql' })
      if (result.success) {
        return { success: true, id }
      }
      return { success: false, error: result.error }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  }

  // 查询角色
  async getRoles(): Promise<Role[]> {
    try {
      const sql = 'SELECT * FROM roles ORDER BY name'
      const result = await window.electronAPI.ai.call(sql, { type: 'sql' })
      if (result.success) {
        return JSON.parse(result.content).map((row: any) => ({
          id: row.id,
          name: row.name,
          tags: JSON.parse(row.tags),
          goldenFinger: row.golden_finger,
          createdAt: row.created_at
        }))
      }
      return []
    } catch (error) {
      console.error('查询角色失败:', error)
      return []
    }
  }
}

