import { useState } from 'react'
import { Button, Space, Card, Input, message, Spin } from 'antd'
import {
  EditOutlined,
  ExpandOutlined,
  CheckCircleOutlined,
  ThunderboltOutlined
} from '@ant-design/icons'
import aiModelService from '../services/aiModels'
import factExtractor from '../services/factExtractor'

const { TextArea } = Input

interface AIToolsPanelProps {
  chapterContent: string
  chapterPath: string | null
  onInsertText: (text: string) => void
}

const AIToolsPanel = ({ chapterContent, chapterPath, onInsertText }: AIToolsPanelProps) => {
  const [generating, setGenerating] = useState(false)
  const [result, setResult] = useState('')
  const [prompt, setPrompt] = useState('')

  // 智能续写
  const handleContinue = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节并编写内容')
      return
    }

    setGenerating(true)
    setResult('')

    try {
      // 获取最后500个字符作为上下文
      const context = chapterContent.slice(-500)
      const fullPrompt = `请继续写下面的小说内容，风格保持一致，衔接自然：

${context}

续写内容：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk, done) => {
          setResult(prev => prev + chunk)
        },
        (error) => {
          message.error(`续写失败：${error}`)
        }
      )
    } catch (error) {
      message.error('续写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 定向扩写
  const handleExpand = async () => {
    if (!prompt) {
      message.warning('请输入扩写要求')
      return
    }

    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请根据以下要求扩写小说内容：
要求：${prompt}
上下文：
${chapterContent.slice(-1000)}

扩写后的内容：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk, done) => {
          setResult(prev => prev + chunk)
        },
        (error) => {
          message.error(`扩写失败：${error}`)
        }
      )
    } catch (error) {
      message.error('扩写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 逻辑校验
  const handleCheck = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }

    setGenerating(true)
    setResult('')

    try {
      const result = await aiModelService.call(
        'logic',
        chapterContent,
        {
          systemPrompt: `请检查以下小说章节内容的逻辑一致性，找出矛盾点、战力崩坏、情节不合理的地方，给出修改建议。`
        }
      )

      if (result.success && result.content) {
        setResult(result.content)
      } else {
        message.error(result.error || '校验失败')
      }
    } catch (error) {
      message.error('逻辑校验失败')
    } finally {
      setGenerating(false)
    }
  }

  // 提取事实
  const handleExtract = async () => {
    if (!chapterContent || !chapterPath) {
      message.warning('请先选择章节')
      return
    }

    setGenerating(true)
    setResult('')

    try {
      // 提取章节号
      const chapterMatch = chapterPath.match(/第(\d+)章/)
      const chapterNumber = chapterMatch ? parseInt(chapterMatch[1]) : 1

      const facts = await factExtractor.extract(chapterContent, chapterNumber)

      if (facts.length === 0) {
        setResult('未提取到任何事实')
        return
      }

      // 格式化结果
      let output = `提取到 ${facts.length} 条事实：\n\n`
      facts.forEach((fact, index) => {
        output += `${index + 1}. [${fact.type}] ${fact.subject}${fact.object ? ' → ' + fact.object : ''}\n`
        output += `   ${fact.content} (置信度: ${(fact.confidence * 100).toFixed(0)}%)\n\n`
      })

      output += `是否保存到事实台账？`
      setResult(output)
    } catch (error) {
      message.error('事实提取失败')
    } finally {
      setGenerating(false)
    }
  }

  // 应用生成结果
  const handleApply = () => {
    if (!result) return
    onInsertText(result)
    message.success('已插入内容')
    setResult('')
  }

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      <div style={{ padding: 16, borderBottom: '1px solid #e8e8e8' }}>
        <h3 style={{ margin: '0 0 10px 0' }}>AI 工具</h3>
        <Space direction="vertical" style={{ width: '100%' }}>
          <Button
            type="primary"
            block
            icon={<EditOutlined />}
            onClick={handleContinue}
            loading={generating}
            disabled={!chapterContent}
          >
            智能续写
          </Button>
          <Button
            block
            icon={<ExpandOutlined />}
            onClick={handleExpand}
            loading={generating}
            disabled={!chapterContent}
          >
            定向扩写
          </Button>
          <Button
            block
            icon={<CheckCircleOutlined />}
            onClick={handleCheck}
            loading={generating}
            disabled={!chapterContent}
          >
            逻辑校验
          </Button>
          <Button
            block
            icon={<ThunderboltOutlined />}
            onClick={handleExtract}
            loading={generating}
            disabled={!chapterContent}
          >
            提取事实
          </Button>

          <TextArea
            placeholder="输入扩写/修改要求（可选）"
            rows={3}
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
          />
        </Space>
      </div>

      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {generating ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="AI 生成中..." />
          </div>
        ) : result ? (
          <Card
            size="small"
            title="AI 生成结果"
            extra={
              <Button
                type="link"
                size="small"
                onClick={handleApply}
              >
                插入到编辑器
              </Button>
            }
            style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}
          >
            {result}
          </Card>
        ) : (
          <div style={{ color: '#999', textAlign: 'center', padding: 40 }}>
            选择上方工具开始使用 AI 辅助创作
          </div>
        )}
      </div>
    </div>
  )
}

export default AIToolsPanel

